# Claude Code Desktop Notifications - One-Line Installer
# irm https://raw.githubusercontent.com/<YOUR_USERNAME>/windows-desktop-notifications/main/install.ps1 | iex

Write-Host '=== Claude Code Desktop Notifications ===' -ForegroundColor Cyan

$ClaudeDir = "$env:USERPROFILE\.claude"
$NotifyPath = "$ClaudeDir\notify.ps1"
$SettingsPath = "$ClaudeDir\settings.json"

# 1. Deploy notify.ps1
Write-Host '[1/3] Deploying notify.ps1...' -ForegroundColor Yellow
$b64 = ""
[System.IO.File]::WriteAllText($NotifyPath, [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($b64)))
Write-Host '  -> ' $NotifyPath -ForegroundColor Green

# 2. Configure hooks
Write-Host '[2/3] Configuring hooks...' -ForegroundColor Yellow
if (Test-Path $SettingsPath) {
    $settings = Get-Content $SettingsPath -Raw | ConvertFrom-Json
} else {
    $settings = @{}
}
if (-not $settings.hooks) {
    $settings | Add-Member -MemberType NoteProperty -Name hooks -Value @{} -Force
}

$permCmd = 'powershell -NoProfile -ExecutionPolicy Bypass -File "' + $NotifyPath + '" -Title "需要确认" -Message "Claude Code 需要你的权限批准" -SoundFile "chimes.wav"'
$stopCmd = 'powershell -NoProfile -ExecutionPolicy Bypass -File "' + $NotifyPath + '" -Title "任务完成" -Message "Claude Code 已完成当前任务" -SoundFile "tada.wav"'

$newPerm = @{matcher=''; hooks=@(@{type='command'; command=$permCmd; timeout=30; async=$true})}
$newStop = @{matcher=''; hooks=@(@{type='command'; command=$stopCmd; timeout=30; async=$true})}

$h = $settings.hooks
if (-not $h.PermissionRequest) { $h | Add-Member -Name PermissionRequest -Value @() -Force }
$h.PermissionRequest += $newPerm
if (-not $h.Stop) { $h | Add-Member -Name Stop -Value @() -Force }
$h.Stop += $newStop

# 3. Save
Write-Host '[3/3] Saving settings...' -ForegroundColor Yellow
$settings | ConvertTo-Json -Depth 10 | Set-Content $SettingsPath -Encoding UTF8
Write-Host '  -> ' $SettingsPath -ForegroundColor Green

Write-Host ''
Write-Host 'Done! Run /hooks or restart Claude Code.' -ForegroundColor Cyan